  function injectLocalStyles() {
    if (document.getElementById('fxProfileLocalStyles')) return;
    var scoped = scopeCSS(CSS, '.fx-root');
    // إصلاحات إضافيّة: نجعل .fx-root تملأ الحاوية بدلاً من الشاشة بأكملها،
    // ونصلح ارتفاعات .p و.pk لتصير 100% داخل الغلاف بدلاً من 100vh/100dvh
    // (لأن الحاوية المُمرَّرة من الحاقن هي التي تحدِّد الارتفاع الآن).
    var overrides =
      '.fx-root{position:relative;width:100%;height:100%;min-height:100%;overflow:hidden;display:block}' +
      '.fx-root .p{height:100%;min-height:0;max-width:none;margin:0}' +
      '.fx-root .pk{position:absolute;inset:0}' +
      '.fx-root .sc{-webkit-overflow-scrolling:touch;overflow-y:auto;overscroll-behavior:contain}';
    var st = document.createElement('style');
    st.id = 'fxProfileLocalStyles';
    st.textContent = scoped + '\n' + overrides;
    document.head.appendChild(st);
  }

  // نُحمِّل الخطَّ العربي مرَّة واحدة إن لم يكن موجودًا في الصفحة المضيفة
  function injectFonts() {
    if (document.getElementById('fxProfileFont')) return;
    var pre1 = document.createElement('link');
    pre1.rel = 'preconnect'; pre1.href = 'https://fonts.googleapis.com';
    document.head.appendChild(pre1);
    var pre2 = document.createElement('link');
    pre2.rel = 'preconnect'; pre2.href = 'https://fonts.gstatic.com'; pre2.crossOrigin = '';
    document.head.appendChild(pre2);
    var l = document.createElement('link');
    l.id = 'fxProfileFont';
    l.rel = 'stylesheet';
    l.href = 'https://fonts.googleapis.com/css2?family=Noto+Sans+Arabic:wght@400;500;700;800&display=swap';
    document.head.appendChild(l);
  }

  // تشغيل السكربت العادي (غير module) داخل نطاق window كسلوك الـ inline <script>.
  // نستخدم عنصر <script> فعلياً كي تُصبح إعلانات الدوال (function foo(){}) عناصر
  // في نطاق window، وذلك ضروري لأن مستمعات onclick داخل الـ HTML تعتمد على ذلك.
  function runInlineScript() {
    if (window.__FXProfileInlineLoaded) return;
    window.__FXProfileInlineLoaded = true;
    try {
      var s = document.createElement('script');
      s.type = 'text/javascript';
      s.textContent = INLINE_JS;
      document.head.appendChild(s);
    } catch (e) {
      console.error('[FXProfile] inline script error:', e);
    }
  }

  // تشغيل سكربت الـ ES Module (Firebase + Brevo) عبر Blob URL — الطريقة الوحيدة
  // لتشغيل كود يحوي import ... from "https://..." من داخل حَقن ديناميكي.
  function runModuleScript() {
    if (window.__FXProfileModuleLoaded) return;
    window.__FXProfileModuleLoaded = true;
    try {
      var blob = new Blob([MODULE_JS], { type: 'text/javascript' });
      var url  = URL.createObjectURL(blob);
      var s = document.createElement('script');
      s.type = 'module';
      s.src  = url;
      s.onload  = function () { /* ok */ };
      s.onerror = function (e) { console.error('[FXProfile] module script failed:', e); };
      document.head.appendChild(s);
    } catch (e) {
      console.error('[FXProfile] module script error:', e);
    }
  }

  function render(container) {
    if (!container) return;

    injectFonts();
    injectLocalStyles();

    // نظّف الحاوية فقط (لا نلمس أي شيء خارجها)
    while (container.firstChild) container.removeChild(container.firstChild);

    // نضع كل واجهة FXER داخل غلاف واحد اسمه .fx-root حتى تعمل جميع قواعد الـ CSS
    // (لأنَّ الملف الأصلي كان يفترض أن يكون <body> = هذا الغلاف)
    var root = document.createElement('div');
    root.className = 'fx-root';
    root.setAttribute('dir', 'rtl');
    root.setAttribute('lang', 'ar');
    root.innerHTML = HTML;
    container.appendChild(root);

    // ثم شغِّل سكربتات التطبيق بالترتيب الأصلي:
    //   1) السكربت العادي (يعرِّف دوال onclick العامة)
    //   2) سكربت الـ module (يُهيّئ Firebase Auth و Brevo ويُعرِّف aGo/aSw/emConfirm...)
    runInlineScript();
    runModuleScript();
  }

  // سطح API الذي يستدعيه الحاقن — مطابق للنسخة التجريبية السابقة
  window.FXProfile = {
    render: render,
    version: '2.0.0'
  };
